import { Server, Socket } from 'socket.io';

export class EventWindow<T> {
  private events: Array<{ seq: number; data: T }> = [];
  private nextSeq = 1;
  constructor(private readonly windowSize: number) {}

  push(data: T): number {
    const seq = this.nextSeq++;
    this.events.push({ seq, data });
    if (this.events.length > this.windowSize) this.events.shift();
    return seq;
  }

  since(sinceSeq: number): { type: 'delta'; events: Array<{ seq: number; data: T }> } | { type: 'gap' } {
    if (this.events.length === 0 || sinceSeq >= this.events[0].seq - 1) {
      return { type: 'delta', events: this.events.filter((e) => e.seq > sinceSeq) };
    }
    return { type: 'gap' };
  }
}

export function mountWindowedStream<T>(io: Server, topic: string, window: EventWindow<T>, snapshot: () => Promise<{ seq: number; data: T }>): void {
  io.on('connection', (socket: Socket) => {
    socket.on(`${topic}:resync`, async (sinceSeq: number, ack: (resp: { type: 'delta'; events: Array<{ seq: number; data: T }> } | { type: 'snapshot'; seq: number; data: T }) => void) => {
      const result = window.since(sinceSeq);
      if (result.type === 'delta') ack(result);
      else ack({ type: 'snapshot', ...await snapshot() });
    });
  });
}

export function broadcastWindowed<T>(io: Server, topic: string, window: EventWindow<T>, data: T): void {
  const seq = window.push(data);
  io.to(topic).emit(`${topic}:event`, { seq, data });
}

import { Server, Socket } from 'socket.io';
import { AsyncLocalStorage } from 'async_hooks';
import crypto from 'crypto';

export interface SocketScope { connectionId: string; socketId: string; userId?: string; }
export const socketScope = new AsyncLocalStorage<SocketScope>();

export function getSocketScope(): SocketScope | undefined { return socketScope.getStore(); }

export function wrapHandlers(io: Server): void {
  io.on('connection', (socket: Socket) => {
    const ctx: SocketScope = { connectionId: crypto.randomUUID(), socketId: socket.id, userId: (socket.data as { userId?: string }).userId };
    const originalOn = socket.on.bind(socket);
    socket.on = ((event: string, handler: (...args: unknown[]) => unknown) => {
      return originalOn(event, (...args: unknown[]) => socketScope.run(ctx, () => handler(...args)));
    }) as typeof socket.on;
  });
}

import { vi, expect, test } from 'vitest';
import { createTestHarness } from './test-harness';

test('client reconnects after disconnect with exponential delay', async () => {
  const harness = await createTestHarness(() => {});
  vi.useFakeTimers({ shouldAdvanceTime: true });

  try {
    const client = await harness.connect();
    expect(client.connected).toBe(true);

    const reconnectAttempts: number[] = [];
    client.io.on('reconnect_attempt', (n) => reconnectAttempts.push(n));

    harness.io.disconnectSockets(true);
    await vi.advanceTimersByTimeAsync(100);
    await vi.advanceTimersByTimeAsync(2000);

    expect(reconnectAttempts.length).toBeGreaterThan(0);
  } finally {
    vi.useRealTimers();
    await harness.close();
  }
});

