import { Request, Response } from 'express';

export class HealthTracker {
  private events: Array<{ at: number; ok: boolean }> = [];
  constructor(private readonly windowMs: number, private readonly maxErrorRate: number, private readonly minSamples: number) {}

  record(ok: boolean): void {
    const now = Date.now();
    this.events.push({ at: now, ok });
    const cutoff = now - this.windowMs;
    while (this.events.length > 0 && this.events[0].at < cutoff) this.events.shift();
  }

  isHealthy(): { healthy: boolean; sampleCount: number; errorRate: number } {
    const sampleCount = this.events.length;
    if (sampleCount < this.minSamples) return { healthy: true, sampleCount, errorRate: 0 };
    const errors = this.events.filter((e) => !e.ok).length;
    const errorRate = errors / sampleCount;
    return { healthy: errorRate < this.maxErrorRate, sampleCount, errorRate };
  }
}

export function healthTrackingMiddleware(tracker: HealthTracker) {
  return (req: Request, res: Response, next: () => void): void => {
    res.on('finish', () => tracker.record(res.statusCode < 500));
    next();
  };
}

export function readinessHandler(tracker: HealthTracker) {
  return (_req: Request, res: Response): void => {
    const status = tracker.isHealthy();
    res.status(status.healthy ? 200 : 503).json(status);
  };
}

import { Request, Response } from 'express';

function formatSse(event: string, data: unknown, id?: string): string {
  const lines = [`event: ${event}`];
  if (id) lines.push(`id: ${id}`);
  lines.push(`data: ${JSON.stringify(data)}`);
  return lines.join('\n') + '\n\n';
}

export async function streamLongJob(req: Request, res: Response): Promise<void> {
  res.setHeader('Content-Type', 'text/event-stream');
  res.setHeader('Cache-Control', 'no-cache');
  res.setHeader('Connection', 'keep-alive');
  res.flushHeaders();

  let heartbeat: NodeJS.Timeout | null = setInterval(() => res.write(':ping\n\n'), 15_000);
  req.on('close', () => { if (heartbeat) clearInterval(heartbeat); heartbeat = null; });

  try {
    for (let i = 0; i < 100; i++) {
      if (req.destroyed) break;
      await new Promise((r) => setTimeout(r, 100));
      if (Math.random() < 0.01) throw new Error('SIMULATED');
      res.write(formatSse('progress', { step: i + 1, of: 100 }, String(i)));
    }
    res.write(formatSse('done', { ok: true }));
  } catch (e) {
    res.write(formatSse('error', { code: 'STREAM_FAILED', message: e instanceof Error ? e.message : 'unknown' }));
  } finally {
    if (heartbeat) clearInterval(heartbeat);
    res.end();
  }
}

