import type { Redis } from 'ioredis';

export interface FlagStore { get(name: string): Promise<boolean | null>; set(name: string, enabled: boolean): Promise<void>; }

export class RedisFlagStore implements FlagStore {
  constructor(private readonly redis: Redis, private readonly prefix = 'flag:') {}
  async get(name: string): Promise<boolean | null> {
    const value = await this.redis.get(`${this.prefix}${name}`);
    if (value === null) return null;
    return value === '1';
  }
  async set(name: string, enabled: boolean): Promise<void> {
    await this.redis.set(`${this.prefix}${name}`, enabled ? '1' : '0');
  }
}

export class FlagService {
  private cache = new Map<string, { value: boolean; cachedAt: number }>();
  constructor(private readonly store: FlagStore, private readonly ttlMs = 30_000) {}

  async isEnabled(name: string, defaultValue = false): Promise<boolean> {
    const cached = this.cache.get(name);
    if (cached && Date.now() - cached.cachedAt < this.ttlMs) return cached.value;
    const stored = await this.store.get(name);
    const value = stored ?? defaultValue;
    this.cache.set(name, { value, cachedAt: Date.now() });
    return value;
  }

  invalidate(name?: string): void { if (name) this.cache.delete(name); else this.cache.clear(); }
}

import cluster from 'cluster';
import os from 'os';
import { createServer } from 'http';
import express from 'express';
import { Server } from 'socket.io';
import { setupMaster, setupWorker } from '@socket.io/sticky';
import { setupPrimary, createAdapter } from '@socket.io/cluster-adapter';

export function startApp(port: number, mount: (io: Server, app: express.Express) => void): void {
  if (cluster.isPrimary) {
    const httpServer = createServer();
    setupMaster(httpServer, { loadBalancingMethod: 'least-connection' });
    setupPrimary();
    httpServer.listen(port);

    const workers = Math.max(1, os.cpus().length);
    for (let i = 0; i < workers; i++) cluster.fork();
    cluster.on('exit', (worker) => { reporter.write(`worker ${worker.process.pid} died, replacing`); cluster.fork(); });
    return;
  }

  const app = express();
  const httpServer = createServer(app);
  const io = new Server(httpServer);
  io.adapter(createAdapter());
  setupWorker(io);
  mount(io, app);
}

