import mongoose, { Schema } from 'mongoose';

export function attachSlowQueryLogger(thresholdMs: number, log: (msg: string, ctx: Record<string, unknown>) => void): void {
  const ops = ['find', 'findOne', 'findOneAndUpdate', 'updateOne', 'updateMany', 'deleteOne', 'deleteMany', 'aggregate', 'countDocuments'] as const;
  for (const op of ops) {
    const pre = function (this: { _slowStart?: number }) { this._slowStart = Date.now(); };
    const post = function (this: { _slowStart?: number; model?: { modelName: string }; getFilter?: () => unknown; pipeline?: () => unknown }) {
      const elapsed = Date.now() - (this._slowStart ?? Date.now());
      if (elapsed >= thresholdMs) {
        log('mongo.slow_query', {
          model: this.model?.modelName,
          op,
          ms: elapsed,
          filter: this.getFilter?.(),
          pipeline: this.pipeline?.(),
        });
      }
    };
    mongoose.plugin((schema: Schema) => {
      schema.pre(op as never, pre as never);
      schema.post(op as never, post as never);
    });
  }
}

export async function examples() {
  const fast = (ms: number, val: string) => new Promise<string>((r) => setTimeout(() => r(val), ms));
  const fastErr = (ms: number) => new Promise<string>((_, rej) => setTimeout(() => rej(new Error('boom')), ms));

  // all: rejects fast on first failure. Wait for all to resolve, otherwise reject.
  const allWins = await Promise.all([fast(10, 'a'), fast(20, 'b')]); // ['a','b']
  try { await Promise.all([fast(10, 'a'), fastErr(20)]); } catch (e) { /* rejects with boom */ }

  // allSettled: never rejects; per-promise status.
  const settled = await Promise.allSettled([fast(10, 'a'), fastErr(20)]);
  // [{status:'fulfilled', value:'a'}, {status:'rejected', reason: Error('boom')}]

  // any: first FULFILLED wins; rejects only if ALL reject (AggregateError).
  const firstSuccess = await Promise.any([fastErr(5), fast(10, 'b')]); // 'b'

  // race: first SETTLEMENT wins (fulfill or reject).
  try { await Promise.race([fastErr(5), fast(10, 'b')]); } catch (e) { /* boom because faster */ }

  return { allWins, settled, firstSuccess };
}

export type ScalarOp<T> = { op: 'eq'; value: T } | { op: 'ne'; value: T };
export type RangeOp<T extends number | Date> = { op: 'lt'; value: T } | { op: 'lte'; value: T } | { op: 'gt'; value: T } | { op: 'gte'; value: T };
export type SetOp<T> = { op: 'in'; value: ReadonlyArray<T> } | { op: 'nin'; value: ReadonlyArray<T> };
export type StringOp = { op: 'contains'; value: string } | { op: 'startsWith'; value: string };

export type StringQuery = ScalarOp<string> | SetOp<string> | StringOp;
export type NumberQuery = ScalarOp<number> | RangeOp<number> | SetOp<number>;
export type DateQuery = ScalarOp<Date> | RangeOp<Date>;

export type Query<T> = {
  [K in keyof T]?:
    T[K] extends string ? StringQuery :
    T[K] extends number ? NumberQuery :
    T[K] extends Date ? DateQuery :
    ScalarOp<T[K]>;
};

