import { Socket } from 'socket.io';

export class ConnectionCleanup {
  private map = new WeakMap<Socket, Array<() => void>>();

  attach(socket: Socket, dispose: () => void): void {
    let list = this.map.get(socket);
    if (!list) { list = []; this.map.set(socket, list); }
    list.push(dispose);
    socket.once('disconnect', () => {
      const callbacks = this.map.get(socket) ?? [];
      for (const cb of callbacks) { try { cb(); } catch (e) { console.error('[cleanup]', e); } }
      this.map.delete(socket);
    });
  }
}

import { Server } from 'socket.io';
import { z } from 'zod';

const HandshakeQuery = z.object({
  room: z.string().regex(/^[0-9a-f]{24}$/),
  locale: z.enum(['en', 'es', 'he']).default('en'),
  client: z.string().min(1).max(32),
});

export type HandshakeQuery = z.infer<typeof HandshakeQuery>;

export function validateHandshake(io: Server): void {
  io.use((socket, next) => {
    const result = HandshakeQuery.safeParse(socket.handshake.query);
    if (!result.success) {
      const err = new Error('HANDSHAKE_INVALID') as Error & { data?: unknown };
      err.data = result.error.flatten();
      next(err);
      return;
    }
    (socket.data as { handshake: HandshakeQuery }).handshake = result.data;
    next();
  });
}

import { generateKeyPair, exportJWK, JWK, SignJWT, importPKCS8, importJWK } from 'jose';
import crypto from 'crypto';
import { Request, Response } from 'express';

export interface KeyEntry { kid: string; privateKey: import('crypto').KeyObject; publicJwk: JWK; createdAt: number; }

export class JwksKeyset {
  private keys: KeyEntry[] = [];
  private activeKid: string | null = null;

  async addNewKey(): Promise<KeyEntry> {
    const { privateKey, publicKey } = await generateKeyPair('RS256', { extractable: true });
    const publicJwk = await exportJWK(publicKey);
    const kid = crypto.randomBytes(8).toString('hex');
    publicJwk.kid = kid;
    publicJwk.use = 'sig';
    publicJwk.alg = 'RS256';
    const entry: KeyEntry = { kid, privateKey: privateKey as unknown as import('crypto').KeyObject, publicJwk, createdAt: Date.now() };
    this.keys.push(entry);
    this.activeKid = kid;
    return entry;
  }

  retireOldest(): void { if (this.keys.length > 2) this.keys.shift(); }

  async sign(payload: Record<string, unknown>, issuer: string, audience: string, expiresIn: string): Promise<string> {
    if (!this.activeKid) throw new Error('NO_ACTIVE_KEY');
    const active = this.keys.find((k) => k.kid === this.activeKid)!;
    return new SignJWT(payload).setProtectedHeader({ alg: 'RS256', kid: active.kid }).setIssuedAt().setIssuer(issuer).setAudience(audience).setExpirationTime(expiresIn).sign(active.privateKey);
  }

  jwks(): { keys: JWK[] } { return { keys: this.keys.map((k) => k.publicJwk) }; }
}

export function jwksHandler(keyset: JwksKeyset) {
  return (_req: Request, res: Response): void => {
    res.setHeader('Cache-Control', 'public, max-age=300');
    res.json(keyset.jwks());
  };
}

import type { Redis } from 'ioredis';
import { UserModel } from './user.model';

export interface UserSummary { id: string; email: string; name: string; roles: string[]; status: 'active' | 'suspended'; }

export class UserContextCache {
  constructor(private readonly redis: Redis, private readonly ttlSec = 30) {}

  private key(userId: string): string { return `user-ctx:${userId}`; }

  async load(userId: string): Promise<UserSummary | null> {
    const cached = await this.redis.get(this.key(userId));
    if (cached) return JSON.parse(cached) as UserSummary;
    const user = await UserModel.findById(userId).select({ email: 1, name: 1, roles: 1, status: 1 }).lean<{ _id: { toString(): string }; email: string; name: string; roles: string[]; status: 'active' | 'suspended' } | null>();
    if (!user) return null;
    const summary: UserSummary = { id: user._id.toString(), email: user.email, name: user.name, roles: user.roles, status: user.status };
    await this.redis.set(this.key(userId), JSON.stringify(summary), 'EX', this.ttlSec);
    return summary;
  }

  async invalidate(userId: string): Promise<void> { await this.redis.del(this.key(userId)); }
}

