interface TooltipState { content: ReactNode; rect: DOMRect; }

let setShown: ((state: TooltipState | null) => void) | null = null;

export function GlobalTooltipHost(): JSX.Element | null {
  const [shown, setLocal] = useState<TooltipState | null>(null);
  useEffect(() => { setShown = setLocal; return () => { setShown = null; }; }, []);
  if (!shown || typeof document === 'undefined') return null;
  return createPortal(
    <div className="fixed z-50 bg-black/90 text-white text-xs px-2 py-1 rounded pointer-events-none" style={{ left: shown.rect.left + shown.rect.width / 2, top: shown.rect.top - 8, transform: 'translate(-50%, -100%)' }}>
