export function useTooltipTrigger(content: ReactNode): { onMouseEnter: (e: React.MouseEvent<HTMLElement>) => void; onMouseLeave: () => void; onFocus: (e: React.FocusEvent<HTMLElement>) => void; onBlur: () => void } {
  const show = useCallback((target: HTMLElement) => { setShown?.({ content, rect: target.getBoundingClientRect() }); }, [content]);
  const hide = useCallback(() => setShown?.(null), []);
  return {
    onMouseEnter: (e) => show(e.currentTarget),
    onMouseLeave: hide,
    onFocus: (e) => show(e.currentTarget),
    onBlur: hide,
  };
}

import mongoose, { ClientSession } from 'mongoose';
import { AccountModel } from './account.model';
import { ConflictError, NotFoundError } from './errors';

export async function transfer(fromId: string, toId: string, amountCents: number): Promise<void> {
  if (amountCents <= 0) throw new Error('INVALID_AMOUNT');
  const session = await mongoose.startSession();
  try {
    await session.withTransaction(async () => {
      const from = await AccountModel.findOneAndUpdate(
        { _id: fromId, balanceCents: { $gte: amountCents } },
        { $inc: { balanceCents: -amountCents } },
        { session, new: true },
      );
      if (!from) {
        const exists = await AccountModel.exists({ _id: fromId }).session(session);
        if (!exists) throw new NotFoundError('From account');
        throw new ConflictError('Insufficient funds');
      }
      const to = await AccountModel.findByIdAndUpdate(toId, { $inc: { balanceCents: amountCents } }, { session, new: true });
      if (!to) throw new NotFoundError('To account');
    });
  } finally {
    await session.endSession();
  }
}

