import { Server } from 'socket.io';

export async function migrateAndClose(io: Server, opts: { newUrl?: string; drainTimeoutMs: number }): Promise<void> {
  io.emit('server:migrate', { reason: 'SHUTDOWN', newUrl: opts.newUrl, reconnectAfterMs: 500 });

  const start = Date.now();
  while (Date.now() - start < opts.drainTimeoutMs) {
    const remaining = (await io.fetchSockets()).length;
    if (remaining === 0) break;
    await new Promise((r) => setTimeout(r, 500));
  }

  await new Promise<void>((resolve) => io.close(() => resolve()));
}

