export interface SamlIdpConfig { entryPoint: string; cert: string; issuer: string; }
export interface SamlClient { processResponse(idpConfig: { issuer: string; cert: string }, request: { body: { SAMLResponse: string } }): Promise<{ extract: { nameID: string; attributes: Record<string, unknown>; audience: string; conditions: { notBefore: Date; notOnOrAfter: Date }; inResponseTo: string } }>; }

export class SamlVerifier {
  constructor(private readonly redis: Redis, private readonly client: SamlClient) {}

  async verify(req: Request, idpConfig: SamlIdpConfig, expectedAudience: string): Promise<{ ok: true; userId: string } | { ok: false; reason: string }> {
    const body = req.body as { SAMLResponse?: string };
    if (!body.SAMLResponse) return { ok: false, reason: 'NO_RESPONSE' };
    try {
      const parsed = await this.client.processResponse({ issuer: idpConfig.issuer, cert: idpConfig.cert }, { body: { SAMLResponse: body.SAMLResponse } });
      const { extract } = parsed;
      const now = Date.now();
      if (now < extract.conditions.notBefore.getTime() || now >= extract.conditions.notOnOrAfter.getTime()) return { ok: false, reason: 'TIME_INVALID' };
      if (extract.audience !== expectedAudience) return { ok: false, reason: 'WRONG_AUDIENCE' };
      const stored = await this.redis.get(`saml:req:${extract.inResponseTo}`);
      if (!stored) return { ok: false, reason: 'UNKNOWN_REQUEST' };
      await this.redis.del(`saml:req:${extract.inResponseTo}`);
      return { ok: true, userId: extract.nameID };
    } catch (e) { return { ok: false, reason: e instanceof Error ? e.message : 'PARSE_FAILED' }; }
  }
}

