import { useEffect, useState } from 'react';
import type { Socket } from 'socket.io-client';

export function useSocketEvent<T>(socket: Socket, event: string): T | null {
  const [value, setValue] = useState<T | null>(null);
  useEffect(() => {
    const handler = (payload: T): void => setValue(payload);
    socket.on(event, handler);
    return () => { socket.off(event, handler); };
  }, [socket, event]);
  return value;
}

import { Request, Response } from 'express';

export interface UpstreamError extends Error { upstreamStatus?: number; }

export async function proxyTo(upstreamUrl: string, init: RequestInit = {}): Promise<{ status: number; body: unknown }> {
  const res = await fetch(upstreamUrl, init);
  let body: unknown = null;
  try { body = await res.json(); }
  catch {}
  return { status: res.status, body };
}

export function mapUpstreamStatus(upstreamStatus: number): number {
  if (upstreamStatus === 404) return 404;
  if (upstreamStatus === 401 || upstreamStatus === 403) return upstreamStatus;
  if (upstreamStatus === 429) return 429;
  if (upstreamStatus >= 500) return 502;
  if (upstreamStatus >= 400) return 502;
  return upstreamStatus;
}

export async function safeProxy(req: Request, res: Response, upstreamUrl: string): Promise<void> {
  try {
    const upstream = await proxyTo(upstreamUrl);
    const mappedStatus = mapUpstreamStatus(upstream.status);
    if (mappedStatus === 502) { res.status(502).json({ error: 'UPSTREAM_FAILED' }); return; }
    res.status(mappedStatus).json(upstream.body);
  } catch { res.status(502).json({ error: 'UPSTREAM_UNREACHABLE' }); }
}

