  findByEmail(email: string): Promise<User | null>;
  create(input: Omit<User, 'id'>): Promise<User>;
}

import { Model } from 'mongoose';
interface UserDoc { _id: { toString(): string }; email: string; name: string; }

export class MongoUserRepo implements UserRepoPort {
  constructor(private readonly model: Model<UserDoc>) {}
  async findById(id: string): Promise<User | null> {
    const doc = await this.model.findById(id).lean<UserDoc | null>();
    return doc ? this.toUser(doc) : null;
  }
  async findByEmail(email: string): Promise<User | null> {
    const doc = await this.model.findOne({ email: email.toLowerCase() }).lean<UserDoc | null>();
    return doc ? this.toUser(doc) : null;
  }
  async create(input: Omit<User, 'id'>): Promise<User> {
    const doc = await this.model.create({ ...input, email: input.email.toLowerCase() }) as unknown as UserDoc;
    return this.toUser(doc);
  }
  private toUser(doc: UserDoc): User { return { id: doc._id.toString(), email: doc.email, name: doc.name }; }
}

export class InMemoryUserRepo implements UserRepoPort {
  private users = new Map<string, User>();
  async findById(id: string): Promise<User | null> { return this.users.get(id) ?? null; }
  async findByEmail(email: string): Promise<User | null> {
    for (const u of this.users.values()) if (u.email === email.toLowerCase()) return u;
    return null;
  }
  async create(input: Omit<User, 'id'>): Promise<User> {
    const user: User = { id: crypto.randomUUID(), email: input.email.toLowerCase(), name: input.name };
    this.users.set(user.id, user);
    return user;
  }
}

