export interface VersionedSource<T> { currentVersion: number; deltas(fromVersion: number): { type: 'delta'; events: Array<{ version: number; data: T }> } | { type: 'full'; version: number; data: T } | { type: 'in-sync' }; }

export function mountVersionedResync<T>(io: Server, topic: string, source: VersionedSource<T>): void {
  io.on('connection', (socket: Socket) => {
    socket.on(`${topic}:resync`, (clientVersion: number, ack: (resp: { type: 'delta'; events: Array<{ version: number; data: T }> } | { type: 'full'; version: number; data: T } | { type: 'in-sync' }) => void) => {
      if (clientVersion === source.currentVersion) { ack({ type: 'in-sync' }); return; }
      ack(source.deltas(clientVersion));
    });
  });
}

import crypto from 'crypto';
import type { Redis } from 'ioredis';

export interface OAuthFlowState { state: string; codeVerifier: string; createdAt: number; }

export class OAuthFlowStore {
  constructor(private readonly redis: Redis, private readonly ttlSec = 600) {}

  async start(sessionId: string): Promise<OAuthFlowState> {
    const state = crypto.randomBytes(32).toString('base64url');
    const codeVerifier = crypto.randomBytes(32).toString('base64url');
    const value: OAuthFlowState = { state, codeVerifier, createdAt: Date.now() };
    await this.redis.set(`oauth:flow:${sessionId}`, JSON.stringify(value), 'EX', this.ttlSec);
    return value;
  }

  async consume(sessionId: string, returnedState: string): Promise<OAuthFlowState | null> {
    const raw = await this.redis.get(`oauth:flow:${sessionId}`);
    if (!raw) return null;
    const value = JSON.parse(raw) as OAuthFlowState;
    await this.redis.del(`oauth:flow:${sessionId}`);
    if (!crypto.timingSafeEqual(Buffer.from(value.state), Buffer.from(returnedState))) return null;
    return value;
  }
}

