export class Email {
  private constructor(public readonly value: string) {}

  static parse(input: string): Email {
    const normalized = input.trim().toLowerCase();
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(normalized)) throw new InvalidEmailError(input);
    if (normalized.length > 254) throw new InvalidEmailError(input);
    return new Email(normalized);
  }

  static tryParse(input: string): Email | null {
    try { return Email.parse(input); }
    catch { return null; }
  }

  equals(other: Email): boolean { return this.value === other.value; }
  toString(): string { return this.value; }
}

