import { Socket, Server } from 'socket.io';

export interface SocketTraffic { inboundEvents: number; outboundEvents: number; bytesIn: number; bytesOut: number; }

export function trackTraffic(io: Server, onConnect?: (socket: Socket, traffic: SocketTraffic) => void): void {
  io.on('connection', (socket: Socket) => {
    const traffic: SocketTraffic = { inboundEvents: 0, outboundEvents: 0, bytesIn: 0, bytesOut: 0 };
    socket.onAny((_event, ...args) => {
      traffic.inboundEvents++;
      try { traffic.bytesIn += JSON.stringify(args).length; } catch {}
    });
    socket.onAnyOutgoing((_event, ...args) => {
      traffic.outboundEvents++;
      try { traffic.bytesOut += JSON.stringify(args).length; } catch {}
    });
    (socket.data as { traffic: SocketTraffic }).traffic = traffic;
    onConnect?.(socket, traffic);
  });
}

import crypto from 'crypto';
import { Request, Response, NextFunction } from 'express';

export function signRequest(method: string, path: string, body: string, ts: number, secret: string): string {
  const canonical = `${method.toUpperCase()}\n${path}\n${ts}\n${body}`;
  return crypto.createHmac('sha256', secret).update(canonical).digest('hex');
}

export interface KeyResolver { getSecret(keyId: string): Promise<string | null>; }

export function verifyRequestSignature(resolver: KeyResolver, maxAgeSec = 300) {
  return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
    const keyId = req.header('X-Key-Id');
    const ts = req.header('X-Timestamp');
    const signature = req.header('X-Signature');
    if (!keyId || !ts || !signature) { res.status(401).json({ error: 'MISSING_AUTH' }); return; }

    const tsNum = Number(ts);
    if (!Number.isFinite(tsNum) || Math.abs(Date.now() / 1000 - tsNum) > maxAgeSec) { res.status(401).json({ error: 'STALE' }); return; }

    const secret = await resolver.getSecret(keyId);
    if (!secret) { res.status(401).json({ error: 'INVALID_KEY' }); return; }

    const body = req.body instanceof Buffer ? req.body.toString('utf8') : JSON.stringify(req.body ?? {});
    const expected = signRequest(req.method, req.path, body, tsNum, secret);
    const expectedBuf = Buffer.from(expected, 'hex');
    const givenBuf = Buffer.from(signature, 'hex');
    if (expectedBuf.length !== givenBuf.length || !crypto.timingSafeEqual(expectedBuf, givenBuf)) {
      res.status(401).json({ error: 'INVALID_SIGNATURE' });
      return;
    }
    (req as Request & { keyId: string }).keyId = keyId;
    next();
  };
}

import { useEffect, useRef, useState } from 'react';

export function useThrottle<T>(value: T, intervalMs: number): T {
  const [throttled, setThrottled] = useState(value);
  const lastEmitRef = useRef(0);
  const pendingValueRef = useRef<T | null>(null);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    const now = Date.now();
    const elapsed = now - lastEmitRef.current;
    if (elapsed >= intervalMs) {
      lastEmitRef.current = now;
      setThrottled(value);
      return;
    }
    pendingValueRef.current = value;
    if (timerRef.current) return;
    timerRef.current = setTimeout(() => {
      lastEmitRef.current = Date.now();
      timerRef.current = null;
      if (pendingValueRef.current !== null) setThrottled(pendingValueRef.current);
      pendingValueRef.current = null;
    }, intervalMs - elapsed);
  }, [value, intervalMs]);

  useEffect(() => () => { if (timerRef.current) clearTimeout(timerRef.current); }, []);

  return throttled;
}

// node --max-old-space-size=512 dist/server.js

import cluster from 'cluster';

export function startCluster(workerScript: string, options: { workers: number; maxMemoryMB: number; restartAfterRequests?: number }): void {
  if (!cluster.isPrimary) return;

  const requestCounts = new Map<number, number>();

  cluster.setupPrimary({ exec: workerScript, execArgv: [`--max-old-space-size=${options.maxMemoryMB}`] });

  for (let i = 0; i < options.workers; i++) cluster.fork();

  cluster.on('message', (worker, msg: { type?: string; requestId?: string }) => {
    if (msg.type === 'request-done') {
      const count = (requestCounts.get(worker.id) ?? 0) + 1;
      if (options.restartAfterRequests && count >= options.restartAfterRequests) {
        requestCounts.delete(worker.id);
        worker.kill('SIGTERM');
      } else {
        requestCounts.set(worker.id, count);
      }
    }
  });

  cluster.on('exit', (worker) => { requestCounts.delete(worker.id); cluster.fork(); });
}

