import { useState, useCallback } from 'react';
import type { Socket } from 'socket.io-client';

export interface ChatMessage { id: string; localId?: string; text: string; status: 'sending' | 'sent' | 'failed'; }

export function useChat(socket: Socket): { messages: ChatMessage[]; send: (text: string) => void } {
  const [messages, setMessages] = useState<ChatMessage[]>([]);

  const send = useCallback((text: string): void => {
    const localId = crypto.randomUUID();
    setMessages((prev) => [...prev, { id: localId, localId, text, status: 'sending' }]);
    socket.emit('chat:send', text, (res: { ok: true; id: string } | { ok: false; error: string }) => {
      setMessages((prev) => prev.map((m) => {
        if (m.localId !== localId) return m;
        if (res.ok) return { ...m, id: res.id, status: 'sent' };
        return { ...m, status: 'failed' };
      }));
    });
  }, [socket]);

  return { messages, send };
}

import { Server, Socket } from 'socket.io';

export interface PermissionResolver { canSee(userId: string, eventType: string, payload: unknown): Promise<boolean>; }

export class PermissionAwareBroadcaster {
  constructor(private readonly io: Server, private readonly perm: PermissionResolver) {}

  async toRoom(roomId: string, eventType: string, payload: unknown): Promise<{ allowed: number; denied: number }> {
    const sockets = await this.io.in(roomId).fetchSockets();
    let allowed = 0, denied = 0;
    const checks = sockets.map(async (s) => {
      const userId = (s.data as { userId?: string }).userId;
      if (!userId) return { socket: s, ok: false };
      const ok = await this.perm.canSee(userId, eventType, payload);
      return { socket: s, ok };
    });
    const results = await Promise.all(checks);
    for (const { socket, ok } of results) {
      if (ok) { socket.emit(eventType, payload); allowed++; }
      else denied++;
    }
    return { allowed, denied };
  }
}

import express from 'express';
import https from 'https';
import fs from 'fs';
import tls from 'tls';

export function buildMtlsServer(app: express.Express, opts: { serverCertPath: string; serverKeyPath: string; clientCaPath: string; port: number }): https.Server {
  return https.createServer({
    cert: fs.readFileSync(opts.serverCertPath),
    key: fs.readFileSync(opts.serverKeyPath),
    ca: fs.readFileSync(opts.clientCaPath),
    requestCert: true,
    rejectUnauthorized: false,
  }, app).listen(opts.port);
}

export function requireClientCert(allowedCns: ReadonlyArray<string>) {
  return (req: express.Request, res: express.Response, next: express.NextFunction): void => {
    const socket = (req.socket as unknown as tls.TLSSocket);
    if (!socket.authorized) {
      res.status(401).json({ error: 'CLIENT_CERT_REQUIRED', detail: socket.authorizationError?.message });
      return;
    }
    const cert = socket.getPeerCertificate?.();
    const cn = cert?.subject?.CN;
    if (!cn || !allowedCns.includes(cn)) { res.status(403).json({ error: 'CERT_NOT_ALLOWED' }); return; }
    next();
  };
}

