import { Request, Response, NextFunction, ErrorRequestHandler } from 'express';
import mongoose from 'mongoose';

export function mongooseErrorMiddleware(): ErrorRequestHandler {
  return (err: unknown, _req: Request, res: Response, next: NextFunction): void => {
    if (err instanceof mongoose.Error.ValidationError) {
      const fieldErrors: Record<string, string> = {};
      for (const [field, e] of Object.entries(err.errors)) {
        fieldErrors[field] = (e as { message: string }).message;
      }
      res.status(422).json({ error: { code: 'VALIDATION_ERROR', fieldErrors } });
      return;
    }
    if (err instanceof mongoose.Error.CastError) {
      res.status(400).json({ error: { code: 'INVALID_ID', field: err.path } });
      return;
    }
    const dup = err as { code?: number; keyValue?: Record<string, unknown> };
    if (dup.code === 11000) {
      const fields = Object.keys(dup.keyValue ?? {});
      res.status(409).json({ error: { code: 'DUPLICATE', fields } });
      return;
    }
    next(err);
  };
}

