import { Worker, isMainThread, parentPort, workerData } from 'worker_threads';

export function runOnSharedBuffer(size: number, workerScript: string): Promise<Int32Array> {
  const sab = new SharedArrayBuffer(size * Int32Array.BYTES_PER_ELEMENT);
  const view = new Int32Array(sab);
  return new Promise((resolve, reject) => {
    const worker = new Worker(workerScript, { workerData: { sab } });
    worker.on('message', () => resolve(view));
    worker.on('error', reject);
    worker.on('exit', (code) => { if (code !== 0) reject(new Error(`worker_exit_${code}`)); });
  });
}

