interface InsertResult { inserted: number; failed: Array<{ index: number; reason: string }>; }

export async function importBatch<T>(model: Model<T>, docs: ReadonlyArray<T>): Promise<InsertResult> {
  try {
    const result = await model.insertMany(docs, { ordered: false, rawResult: true }) as unknown as { insertedCount: number };
    return { inserted: result.insertedCount, failed: [] };
  } catch (err) {
    const e = err as { insertedDocs?: T[]; writeErrors?: Array<{ index: number; errmsg: string }> };
    const failed = (e.writeErrors ?? []).map((we) => ({ index: we.index, reason: we.errmsg }));
    return { inserted: e.insertedDocs?.length ?? 0, failed };
  }
}

