export function tracedErrorMiddleware(logger: Logger): ErrorRequestHandler {
  return (err: unknown, req: Request, res: Response, _next: NextFunction): void => {
    const requestId = getRequestId() ?? 'unknown';
    if (err instanceof AppError) {
      logger.error('app_error', { requestId, code: err.code, status: err.statusCode, path: req.path });
      res.status(err.statusCode).json({ error: { code: err.code, message: err.message, requestId } });
      return;
    }
    const e = err as Error;
    logger.error('internal_error', { requestId, name: e.name, message: e.message, stack: e.stack, path: req.path });
    res.status(500).json({ error: { code: 'INTERNAL', message: 'An unexpected error occurred', requestId } });
  };
}

