export function buildMessageHandler(deps: MessageHandlerDeps) {
  return async (socket: Socket, msg: { to: string; text: string }, ack: (ok: boolean) => void): Promise<void> => {
    if (!msg.to || !msg.text) { ack(false); return; }
    await deps.sendNotification(msg.to, msg.text);
    socket.to(`user:${msg.to}`).emit('message:incoming', { from: (socket.data as { userId: string }).userId, text: msg.text });
    ack(true);
  };
}

