import { useCallback, useEffect, useState } from 'react';

function coerce<T extends Record<string, string | number | boolean | undefined>>(initial: T, params: URLSearchParams): T {
  const next: Record<string, unknown> = { ...initial };
  for (const key of Object.keys(initial)) {
    const value = params.get(key);
    if (value === null) continue;
    const init = (initial as Record<string, unknown>)[key];
    if (typeof init === 'number') next[key] = Number(value);
    else if (typeof init === 'boolean') next[key] = value === 'true';
    else next[key] = value;
  }
  return next as T;
}

export function useUrlState<T extends Record<string, string | number | boolean | undefined>>(initial: T): [T, (next: Partial<T>) => void] {
  const read = useCallback((): T => {
    if (typeof window === 'undefined') return initial;
    return coerce(initial, new URLSearchParams(window.location.search));
  }, [initial]);

  const [state, setState] = useState<T>(read);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    const onPopState = (): void => setState(read());
    window.addEventListener('popstate', onPopState);
    return () => window.removeEventListener('popstate', onPopState);
  }, [read]);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    const params = new URLSearchParams();
    for (const [key, value] of Object.entries(state)) {
      if (value === undefined || value === '' || value === false) continue;
      params.set(key, String(value));
    }
    const qs = params.toString();
    const nextUrl = `${window.location.pathname}${qs ? `?${qs}` : ''}${window.location.hash}`;
    window.history.replaceState(window.history.state, '', nextUrl);
  }, [state]);

  const update = useCallback((next: Partial<T>) => setState((prev) => ({ ...prev, ...next })), []);
  return [state, update];
}

import { AsyncLocalStorage } from 'async_hooks';

interface RequestBudget { totalMs: number; deadlineMs: number; }
const budgetScope = new AsyncLocalStorage<RequestBudget>();

export function startBudget<T>(totalMs: number, fn: () => Promise<T>): Promise<T> {
  return budgetScope.run({ totalMs, deadlineMs: Date.now() + totalMs }, fn);
}

export function remainingMs(): number {
  const budget = budgetScope.getStore();
  if (!budget) return Infinity;
  return Math.max(0, budget.deadlineMs - Date.now());
}

export async function upstreamCall<T>(work: (signal: AbortSignal) => Promise<T>, fractionOfBudget = 0.5, hardCapMs = 5000): Promise<T> {
  const limit = Math.min(hardCapMs, Math.floor(remainingMs() * fractionOfBudget));
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), limit);
  try { return await work(controller.signal); }
  finally { clearTimeout(timer); }
}

export interface Mongoose { connection: { readyState: number }; connect(uri: string): Promise<unknown>; }

export function lazyConnection(uriProvider: () => string, connect: () => Promise<Mongoose>): () => Promise<Mongoose> {
  let instance: Mongoose | null = null;
  let inflight: Promise<Mongoose> | null = null;
  return async () => {
    if (instance) return instance;
    if (inflight) return inflight;
    inflight = (async () => {
      const m = await connect();
      instance = m;
      inflight = null;
      return m;
    })();
    return inflight;
  };
}

