import { useActionState, useId } from 'react';

interface FormState { ok: boolean; error?: string; }

async function submitProfile(_prev: FormState, formData: FormData): Promise<FormState> {
  const name = formData.get('name');
  if (typeof name !== 'string' || name.trim().length === 0) return { ok: false, error: 'NAME_REQUIRED' };
  const res = await fetch('/api/profile', { method: 'POST', body: JSON.stringify({ name: name.trim() }), headers: { 'Content-Type': 'application/json' } });
  if (!res.ok) return { ok: false, error: 'SAVE_FAILED' };
  return { ok: true };
}

export function ProfileForm(): JSX.Element {
  const [state, action, isPending] = useActionState(submitProfile, { ok: false });
  const nameId = useId();
  const messageId = useId();

  return (
    <form action={action} className="space-y-2" aria-describedby={messageId}>
      <label htmlFor={nameId} className="block text-sm font-medium">Name</label>
      <input id={nameId} name="name" required disabled={isPending} aria-invalid={state.error ? true : undefined} aria-describedby={messageId} className="border rounded px-2 py-1" />
      <button type="submit" disabled={isPending} className="px-4 py-1 bg-blue-600 text-white rounded disabled:opacity-50">{isPending ? 'Saving...' : 'Save'}</button>
      {state.error && <p id={messageId} role="alert" className="text-red-600 text-sm">{state.error}</p>}
      {state.ok && <p id={messageId} role="status" className="text-green-600 text-sm">Saved!</p>}
    </form>
  );
}

export const HTTP_STATUS = {
  OK: 200,
  CREATED: 201,
  NO_CONTENT: 204,
  BAD_REQUEST: 400,
  UNAUTHORIZED: 401,
  FORBIDDEN: 403,
  NOT_FOUND: 404,
  CONFLICT: 409,
  RATE_LIMITED: 429,
  INTERNAL: 500,
} as const;

export type HttpStatusName = keyof typeof HTTP_STATUS;
export type HttpStatusCode = typeof HTTP_STATUS[HttpStatusName];

export function statusName(code: number): HttpStatusName | null {
  for (const [name, value] of Object.entries(HTTP_STATUS) as Array<[HttpStatusName, HttpStatusCode]>) {
    if (value === code) return name;
  }
  return null;
}

