import { jwtVerify, importSPKI } from 'jose';

export interface PinnedKeyConfig { publicKeyPem: string; algorithm: 'RS256' | 'ES256'; issuer: string; audience: string; }

export class PinnedKeyVerifier {
  private keyPromise: Promise<import('crypto').KeyObject> | null = null;
  constructor(private readonly cfg: PinnedKeyConfig) {}

  private async key(): Promise<import('crypto').KeyObject> {
    if (!this.keyPromise) this.keyPromise = importSPKI(this.cfg.publicKeyPem, this.cfg.algorithm) as Promise<import('crypto').KeyObject>;
    return this.keyPromise;
  }

  async verify(token: string): Promise<{ userId: string }> {
    const key = await this.key();
    const { payload } = await jwtVerify(token, key, { issuer: this.cfg.issuer, audience: this.cfg.audience, algorithms: [this.cfg.algorithm] });
    return { userId: payload.sub as string };
  }
}

import { useEffect, useRef, useState } from 'react';

interface EditorProps { initialValue: string; resetKey?: string; onChange: (v: string) => void; }

export function ResettableEditor({ initialValue, resetKey, onChange }: EditorProps): JSX.Element {
  const [value, setValue] = useState(initialValue);
  const previousResetKey = useRef(resetKey);

  useEffect(() => {
    if (resetKey === undefined || Object.is(previousResetKey.current, resetKey)) return;
    previousResetKey.current = resetKey;
    setValue(initialValue);
  }, [resetKey, initialValue]);

  return (
    <input value={value} onChange={(e) => { const next = e.target.value; setValue(next); onChange(next); }} />
  );
}

