export interface UserEntity { id: string; createdAt: Date; lastLoginAt: Date | null; }
export interface UserDto { id: string; createdAt: string; lastLoginAt: string | null; }

export function dateToIso(d: Date): string { return d.toISOString(); }
export function maybeDateToIso(d: Date | null): string | null { return d ? d.toISOString() : null; }
export function isoToDate(s: string): Date {
  const d = new Date(s);
  if (Number.isNaN(d.getTime())) throw new Error(`INVALID_DATE: ${s}`);
  return d;
}
export function maybeIsoToDate(s: string | null): Date | null { return s ? isoToDate(s) : null; }

export const UserMapper = {
  toDto(entity: UserEntity): UserDto {
    return { id: entity.id, createdAt: dateToIso(entity.createdAt), lastLoginAt: maybeDateToIso(entity.lastLoginAt) };
  },
  fromDto(dto: UserDto): UserEntity {
    return { id: dto.id, createdAt: isoToDate(dto.createdAt), lastLoginAt: maybeIsoToDate(dto.lastLoginAt) };
  },
};

