export class TimeoutError extends Error { constructor(public readonly ms: number) { super(`TIMEOUT_${ms}ms`); this.name = 'TimeoutError'; } }

export async function fetchWithBudget(url: string, init: RequestInit = {}, ms: number): Promise<Response> {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), ms);
  try {
    const res = await fetch(url, { ...init, signal: controller.signal });
    return res;
  } catch (err) {
    if (err instanceof DOMException && err.name === 'AbortError') throw new TimeoutError(ms);
    throw err;
  } finally {
    clearTimeout(timer);
  }
}

