import type { Redis } from 'ioredis';

export class AdapterHealthMonitor {
  private healthy = true;
  constructor(private readonly pub: Redis, private readonly sub: Redis) {
    pub.on('end', () => { this.healthy = false; });
    pub.on('error', () => { this.healthy = false; });
    pub.on('ready', () => { this.healthy = true; });
    sub.on('end', () => { this.healthy = false; });
    sub.on('error', () => { this.healthy = false; });
    sub.on('ready', () => { this.healthy = true; });
  }

  async deepCheck(): Promise<boolean> {
    try { await this.pub.ping(); await this.sub.ping(); return this.healthy; }
    catch { return false; }
  }

  get status(): boolean { return this.healthy; }
}

import express, { Request, Response, NextFunction } from 'express';

const ALLOWED_METHODS = new Set(['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS', 'HEAD']);

export function methodAllowlist() {
  return (req: Request, res: Response, next: NextFunction): void => {
    if (!ALLOWED_METHODS.has(req.method)) {
      res.status(405).setHeader('Allow', Array.from(ALLOWED_METHODS).join(', ')).json({ error: 'METHOD_NOT_ALLOWED' });
      return;
    }
    next();
  };
}

