import { AppError, ConflictError, NotFoundError, ValidationError } from './errors';
import type Stripe from 'stripe';

export class PaymentProviderError extends AppError {
  readonly statusCode = 502;
  readonly code = 'PAYMENT_PROVIDER';
}

export function translateStripeError(err: unknown): AppError {
  const e = err as Stripe.errors.StripeError;
  if (!e?.type) return new PaymentProviderError('Unknown payment error');
  switch (e.type) {
    case 'StripeCardError': return new ValidationError(e.message ?? 'Card declined');
    case 'StripeInvalidRequestError': return new ValidationError(e.message ?? 'Invalid request');
    case 'StripeIdempotencyError': return new ConflictError('Idempotency conflict');
    case 'StripeAPIError':
    case 'StripeConnectionError':
      return new PaymentProviderError('Payment provider unavailable');
    default: return new PaymentProviderError(e.message ?? 'Payment error');
  }
}

export async function safeStripeCall<T>(fn: () => Promise<T>): Promise<T> {
  try { return await fn(); }
  catch (err) { throw translateStripeError(err); }
}

import { Request, Response, NextFunction } from 'express';

export interface RequestScope<T> { resolve<K extends keyof T>(key: K): T[K]; cleanup(): Promise<void>; }

export function createRequestScope<T extends Record<string, unknown>>(
  factories: { [K in keyof T]: () => T[K] | Promise<T[K]> },
  disposers?: { [K in keyof T]?: (value: T[K]) => Promise<void> },
): () => RequestScope<T> {
  return () => {
    const cache = new Map<keyof T, unknown>();
    return {
      async resolve<K extends keyof T>(key: K): Promise<T[K]> {
        if (cache.has(key)) return cache.get(key) as T[K];
        const value = await factories[key]();
        cache.set(key, value);
        return value;
      },
      async cleanup(): Promise<void> {
        if (!disposers) return;
        for (const [key, value] of cache.entries()) {
          const disposer = disposers[key as keyof T];
          if (disposer) await disposer(value as T[keyof T]);
        }
      },
    } as unknown as RequestScope<T>;
  };
}

export function scopeMiddleware<T extends Record<string, unknown>>(create: () => RequestScope<T>) {
  return (req: Request, res: Response, next: NextFunction): void => {
    const scope = create();
    (req as Request & { scope: RequestScope<T> }).scope = scope;
    res.on('finish', () => { void scope.cleanup(); });
    res.on('close', () => { void scope.cleanup(); });
    next();
  };
}

