export class AdminBroadcaster {
  constructor(private readonly io: Server) {}

  toUsers(userIds: ReadonlyArray<string>, event: string, payload: unknown): void {
    if (userIds.length === 0) return;
    const rooms = userIds.map((id) => `user:${id}`);
    this.io.to(rooms).emit(event, payload);
  }

  async forceDisconnect(userId: string): Promise<void> {
    await this.io.in(`user:${userId}`).disconnectSockets(true);
  }

  async kickEveryone(): Promise<void> {
    await this.io.disconnectSockets(true);
  }
}

import crypto from 'crypto';

export interface PwnedChecker { isPwned(password: string): Promise<{ pwned: boolean; count: number }>; }

export class HibpPwnedChecker implements PwnedChecker {
  async isPwned(password: string): Promise<{ pwned: boolean; count: number }> {
    const sha1 = crypto.createHash('sha1').update(password).digest('hex').toUpperCase();
    const prefix = sha1.slice(0, 5);
    const suffix = sha1.slice(5);
    const res = await fetch(`https://api.pwnedpasswords.com/range/${prefix}`, { headers: { 'Add-Padding': 'true' } });
    if (!res.ok) throw new Error(`HIBP_${res.status}`);
    const body = await res.text();
    for (const line of body.split(/\r?\n/)) {
      const [lineSuffix, countStr] = line.split(':');
      if (lineSuffix === suffix) return { pwned: true, count: Number(countStr) };
    }
    return { pwned: false, count: 0 };
  }
}

import { useState } from 'react';

interface NumericInputProps { initial?: number; min?: number; max?: number; onChange?: (value: number | null) => void; }

export function NumericInput({ initial, min, max, onChange }: NumericInputProps): JSX.Element {
  const [text, setText] = useState(initial !== undefined ? String(initial) : '');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>): void => {
    const next = e.target.value;
    setText(next);
    if (next === '') { onChange?.(null); return; }
    const num = Number(next);
    if (!Number.isFinite(num)) { onChange?.(null); return; }
    if (min !== undefined && num < min) { onChange?.(null); return; }
    if (max !== undefined && num > max) { onChange?.(null); return; }
    onChange?.(num);
  };

  return <input type="text" inputMode="numeric" pattern="-?\\d*(\\.\\d+)?" value={text} onChange={handleChange} />;
}

